logger = logging.getLogger(__name__)


def detect_container_windows(pid: int) -> ContainerInfo:
    """Walk the parent process chain to identify the containing application."""
    container = ContainerInfo()

    try:
        claude_proc = psutil.Process(pid)
        bash_proc = claude_proc.parent()
        if not bash_proc:
            return container

        # Extract only needed env vars
        term_program = ""
        try:
            full_env = bash_proc.environ()
            term_program = full_env.get("TERM_PROGRAM", "").lower()
            del full_env
        except (psutil.AccessDenied, psutil.NoSuchProcess):
            pass

        # Walk up the process chain
        current = bash_proc
        while current:
            name = current.name().lower()

            if "code" in name and name.endswith(".exe"):
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = ContainerType.VSCODE
                break

            if name in ("windowsterminal.exe", "wt.exe", "cmd.exe"):
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = ContainerType.TERMINAL
                break

            if name == "mintty.exe":
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = ContainerType.GITBASH
                break

            try:
                current = current.parent()
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                break

        # Fallback from env
        if container.container_type == ContainerType.UNKNOWN and term_program == "vscode":
            container.container_type = ContainerType.VSCODE

    except (psutil.NoSuchProcess, psutil.AccessDenied):
        pass

    return container


def _find_main_vscode_pid(start_pid: int) -> int:
    """Walk up from a VS Code child process to the main VS Code process.

    The main process is the one whose parent is NOT Code.exe
    (typically explorer.exe). All windows are owned by this process.
    """
    try:
        proc = psutil.Process(start_pid)
        while proc.parent() and proc.parent().name().lower() == "code.exe":
            proc = proc.parent()
        return proc.pid
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        return start_pid


def match_window_by_cwd(cwd: str, container: ContainerInfo) -> ContainerInfo:
    """Find the VS Code window matching a session's CWD by title matching."""
    if container.container_type != ContainerType.VSCODE or container.process_pid == 0:
        return container

    try:
        from ctypes import wintypes

        user32 = ctypes.windll.user32
        WNDENUMPROC = ctypes.WINFUNCTYPE(ctypes.c_bool, wintypes.HWND, wintypes.LPARAM)

        folder_name = Path(cwd).name.lower()
        main_pid = _find_main_vscode_pid(container.process_pid)

        best_match = None

        def enum_cb(hwnd, _):
            nonlocal best_match
            if user32.IsWindowVisible(hwnd):
                pid = wintypes.DWORD()
                user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
                if pid.value == main_pid:
                    length = user32.GetWindowTextLengthW(hwnd)
                    if length > 0:
                        buf = ctypes.create_unicode_buffer(length + 1)
                        user32.GetWindowTextW(hwnd, buf, length + 1)
                        title = buf.value
                        if folder_name in title.lower():
                            best_match = (hwnd, title)
            return True

        user32.EnumWindows(WNDENUMPROC(enum_cb), 0)

        if best_match:
            container.window_handle = best_match[0]
            container.window_title = best_match[1]
        else:
            logger.debug(
                "no VS Code window matched folder=%s main_pid=%d",
                folder_name,
                main_pid,
            )

    except Exception as exc:
        logger.debug("window matching failed error=%s", exc)

    return container


def foreground_window_windows(hwnd: int) -> bool:
    """Bring a window to the foreground using SetForegroundWindow."""
    user32 = ctypes.windll.user32

    # Restore if minimized
    SW_RESTORE = 9
    if user32.IsIconic(hwnd):
        user32.ShowWindow(hwnd, SW_RESTORE)

    # Try direct foreground
    result = user32.SetForegroundWindow(hwnd)
    if result:
        return True

    # Fallback: Alt key trick for foreground permission
    VK_ALT = 0x12
    KEYEVENTF_EXTENDEDKEY = 0x0001
    KEYEVENTF_KEYUP = 0x0002

    user32.keybd_event(VK_ALT, 0, KEYEVENTF_EXTENDEDKEY, 0)
    result = user32.SetForegroundWindow(hwnd)
    user32.keybd_event(VK_ALT, 0, KEYEVENTF_EXTENDEDKEY | KEYEVENTF_KEYUP, 0)

    return bool(result)
